javascript// Gerenciador de câmera que ajusta viewport automaticamente
class SmartCamera {
  constructor() {
    this.currentSection = null;
    this.cameraPosition = { x: 0, y: 0, z: 0 };
  }

  // Ajusta câmera baseado no conteúdo visível
  adjustForContent(section) {
    const contentHeight = section.scrollHeight;
    const viewportHeight = window.innerHeight;

    if (contentHeight > viewportHeight * 1.5) {
      // Conteúdo alto - ativa modo scroll progressivo
      this.enableProgressiveReveal(section);
    } else {
      // Conteúdo normal - animação padrão
      this.enableStandardAnimation(section);
    }
  }

  enableProgressiveReveal(section) {
    const elements = section.querySelectorAll('[data-reveal]');

    elements.forEach((el, index) => {
      gsap.to(el, {
        scrollTrigger: {
          trigger: section,
          start: 'top top',
          end: 'bottom bottom',
          scrub: 1,
          onUpdate: (self) => {
            const progress = self.progress;
            const threshold = index / elements.length;

            if (progress >= threshold) {
              el.style.opacity = Math.min((progress - threshold) * elements.length, 1);
              el.style.transform = `translateY(${(1 - (progress - threshold) * elements.length) * 100}px)`;
            }
          }
        }
      });
    });

    // Ajusta posição Y da câmera
    gsap.to(this.cameraPosition, {
      scrollTrigger: {
        trigger: section,
        start: 'top top',
        end: 'bottom bottom',
        scrub: 1
      },
      y: -(section.scrollHeight - window.innerHeight),
      ease: 'none'
    });
  }
}

// Inicializa câmera inteligente
const camera = new SmartCamera();
document.querySelectorAll('section').forEach(section => {
  camera.adjustForContent(section);
});

